const BB = "https://www.bbassets.com/media/uploads/p/l/";

function p(price: number, origPrice: number): { price: number; originalPrice: number; discount: number } {
  const pr = Math.ceil(price);
  const op = Math.ceil(origPrice);
  return { price: pr, originalPrice: op, discount: Math.round(((op - pr) / op) * 100) };
}

