export function getBBProductsForCategory(categorySlug: string): BBProduct[] {
  return BB_PRODUCTS[categorySlug] || [];
}

export function getAllBBCategories(): BBCategory[] {
  return BB_CATEGORIES;
}

export function getAllBBProducts(): { category: BBCategory; products: BBProduct[] }[] {
  return BB_CATEGORIES.map(cat => ({
    category: cat,
    products: BB_PRODUCTS[cat.slug] || [],
  })).filter(entry => entry.products.length > 0);
}
